import{_ as i,o as s,c as e,ak as t}from"./chunks/framework.Dpc0wyhY.js";const k=JSON.parse('{"title":"API Quickstart","description":"","frontmatter":{},"headers":[],"relativePath":"api-quickstart.md","filePath":"api-quickstart.md"}'),n={name:"api-quickstart.md"};function l(h,a,r,o,p,d){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="api-quickstart" tabindex="-1">API Quickstart <a class="header-anchor" href="#api-quickstart" aria-label="Permalink to “API Quickstart”">​</a></h1><p>Get started with the REST API. Learn to interact with collections, fetch, and create data.</p><p>This guide covers interacting with collections via the REST API. You will fetch and create data, and make your first requests.</p><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to “Before You Start”">​</a></h2><p>You will need a Likha ERP project with a collection created. Create a <code>posts</code> collection with at least a <code>title</code> and <code>content</code> field.</p><p>You also need an access token. In the management interface, go to your user detail page. Create a new token, take note of it, and then save.</p><h2 id="fetching-data" tabindex="-1">Fetching Data <a class="header-anchor" href="#fetching-data" aria-label="Permalink to “Fetching Data”">​</a></h2><p>Open your terminal and run the following command to read items from the <code>posts</code> collection.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--header </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Authorization: Bearer YOUR_ACCESS_TOKEN&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--url </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;https://your-domain.com/api/items/posts&#39;</span></span></code></pre></div><p><strong>Replace values:</strong></p><ul><li>The Base URL (<code>https://your-domain.com</code>) must be replaced with your project URL.</li><li>In the Authorization Header, replace <code>YOUR_ACCESS_TOKEN</code> with your access token.</li><li>If you used a different collection, replace <code>posts</code> with the name of the collection.</li></ul><p>The API will respond with an array of items. The default limit is 100, so if there are more than 100 items, you must either provide a higher limit or request a second page using pagination.</p><h2 id="using-query-parameters" tabindex="-1">Using Query Parameters <a class="header-anchor" href="#using-query-parameters" aria-label="Permalink to “Using Query Parameters”">​</a></h2><p>You can use any of the global query parameters to change the data that is returned.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --header</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Authorization: Bearer YOUR_ACCESS_TOKEN&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://your-domain.com/api/items/posts?filter[status][_eq]=published&amp;fields=id,title&#39;</span></span></code></pre></div><p>This request will only show items with a <code>status</code> value of <code>published</code>, and only return the <code>id</code> and <code>title</code> fields.</p><p>See all available query parameters in the Query Parameters guide.</p><h2 id="creating-data" tabindex="-1">Creating Data <a class="header-anchor" href="#creating-data" aria-label="Permalink to “Creating Data”">​</a></h2><p>All collections are given consistent endpoints. By sending a POST request to <code>/api/items/posts</code> with an object containing properties in the collection, a new item will be created.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	--request</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	--header</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Authorization: Bearer YOUR_ACCESS_TOKEN&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	--header</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	--data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{ &quot;title&quot;: &quot;Hello Universe!&quot; }&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  	--url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://your-domain.com/api/items/posts&#39;</span></span></code></pre></div>`,20)])])}const u=i(n,[["render",l]]);export{k as __pageData,u as default};
